Code.Terraform:
```hcl
# 为 OpenSearch 域启用 AUDIT_LOGS
resource "aws_opensearch_domain" "example" {
  domain_name = "<example_resource_name>"

  log_publishing_options {
    log_type                 = "AUDIT_LOGS"
    cloudwatch_log_group_arn = "<CLOUDWATCH_LOG_GROUP_ARN>"  # 关键：审计日志的目的地
    enabled                  = true                           # 关键：启用 AUDIT_LOGS 以通过检查
  }
}
```
